import * as React from "react"
import { cn } from "@/lib/utils"
import { Input } from "@/components/ui/input"

export interface AddonInputProps extends React.ComponentProps<typeof Input> {
  prefixAddon?: React.ReactNode
  suffixAddon?: React.ReactNode
}

/**
 * AddonInput - A specialized input component that supports text or icon addons.
 * It uses a flex container to join the addon and the input with a shared border.
 * 
 * @example
 * <AddonInput prefixAddon="https://" placeholder="example.com" />
 */
const AddonInput = React.forwardRef<HTMLInputElement, AddonInputProps>(
  ({ className, prefixAddon, suffixAddon, ...props }, ref) => {
    return (
      <div className="flex -space-x-px w-full">
        {prefixAddon && (
          <span className="inline-flex items-center rounded-l-(--radius) border border-border bg-muted/50 px-3 text-sm text-muted-foreground select-none whitespace-nowrap">
            {prefixAddon}
          </span>
        )}
        <Input
          ref={ref}
          className={cn(
            prefixAddon && "rounded-l-none",
            suffixAddon && "rounded-r-none",
            "focus-visible:z-10",
            className
          )}
          {...props}
        />
        {suffixAddon && (
          <span className="inline-flex items-center rounded-r-(--radius) border border-border bg-muted/50 px-3 text-sm text-muted-foreground select-none whitespace-nowrap">
            {suffixAddon}
          </span>
        )}
      </div>
    )
  }
)
AddonInput.displayName = "AddonInput"

export { AddonInput }
